/**
 * Export Routes
 *
 * REST endpoints for exporting PM schedules (Excel/CSV) and generating reports (PDF).
 * Uses async job processing with status polling.
 *
 * Key endpoints:
 * - POST /export/pm-schedule - Queue PM schedule export
 * - POST /export/report - Queue report generation
 * - GET /export/:jobId - Get export job status and download URL
 * - GET /export/jobs - List export jobs for current user
 *
 * @see specs/005-api.md Section 5.15
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
